        {
            public LockedChestStateMachine()
            {
                AddState(new IdleState());
                AddState(new JumpState());
                AddState(new ChargeState());
                AddState(new HighJumpState());
                AddState(new LockState());
                AddState(new CrushingLockState());

                AddState(new SpitTrashState());
                AddState(new CoughState());
                AddState(new SpecialAttackState());
                AddState(new ReleaseSpecialAttackState());

                AddState(new CameraState());

                AddState(new SpitZombieBlueprintState());

                AddState(new PayToWinState());
                AddState(new FiveSmashesState());
                AddState(new HyperbeamState());
                AddState(new FourSoulsState());

                AddState(new StunnedState());
                AddState(new DeathState());


                AddState(new BombardState());
                AddState(new SummonWitherState());
                AddState(new GiantizeState());
                AddState(new FireBreathState());

                AddState(new TiredState());
            }
        }
