        private static int GetShadowVariant(Entity entity, bool front)
        {
            int variant = 0;
            if (GetPhase(entity) == PHASE_2)
            {
                variant |= 1;
            }
            if (front)
            {
                variant |= 2;
            }
            return variant;
        }
        private static void SpawnShadow(Entity entity, bool front = false)
        {
            var param = entity.GetSpawnParams();
            param.SetProperty(EngineEntityProps.DISPLAY_SCALE, entity.GetDisplayScale());
            param.SetProperty(EngineEntityProps.FLIP_X, entity.IsFlipX());
            param.SetProperty(LogicEntityProps.VARIANT, GetShadowVariant(entity, front));
            entity.Spawn(VanillaEffectID.lockedChestShadow, entity.Position, param);
        }
        private static void SetShake(Entity entity, bool value)
        {
            entity.SetAnimationBool("Shake", value);
        }
        private static void SetEmote(Entity entity, int value)
        {
            entity.SetAnimationInt("Emote", value);
        }
        private static bool IsValidAttackTarget(Entity chest, Entity target)
        {
            return chest.IsHostile(target) && target.IsVulnerableEntity() && !target.IsInvincible() && Detection.CanDetect(target);
        }
        private static bool HasAnyEnemy(Entity entity)
        {
            var level = entity.Level;
            return level.EntityExists(e => IsValidAttackTarget(entity, e));
        }
        private static int FindRandomLaneWithEnemies(Entity entity)
        {
            var level = entity.Level;
            var contraptions = level.FindEntities(e => IsValidAttackTarget(entity, e));
            var groups = contraptions.GroupBy(c => c.GetLane());
            return groups.Random(entity.RNG).Key;
        }
        private static void UpdateFlipX(Entity entity)
        {
            SetFlipX(entity, entity.Position.x < entity.Level.GetLawnCenterX());
        }
        private static void Hop(Entity entity, float speed = 10)
        {
            entity.Velocity = Vector3.up * speed;
        }
        #region 待命
        private static bool CanSwitchStatePhase1(Entity entity, int state)
        {
            switch (state)
            {
                case STATE_SMASH:
                    return FindHighJumpSmashTargetEntity(entity) != null;
                case STATE_LOCK:
                    return CanSwitchToLockState(entity);
                case STATE_CRUSHING_LOCK:
                    return CanSwitchToCrushingLockState(entity);
            }
            return true;
        }
        private static bool CanSwitchStatePhase2(Entity entity, int state)
        {
            switch (state)
            {
                case STATE_SMASH:
                    return FindHighJumpSmashTargetEntity(entity) != null;
                case STATE_SPIT_TRASH:
                    return CanSwitchToSpitTrashState(entity);
                case STATE_CAMERA:
                    return CanSwitchToCameraState(entity);
                case STATE_PAY_TO_WIN:
                    return CanSwitchToPayToWinState(entity);
            }
            return true;
        }
        private static void SwitchState(Entity entity, int state)
        {
            switch (state)
            {
                case STATE_SPIT_TRASH:
                case STATE_PAY_TO_WIN:
                case STATE_BOMBARD:
                case STATE_SUMMON_WITHER:
                case STATE_GIANTIZE:
                case STATE_FIREBREATH:
                    {
                        JumpTo(entity, GetStateJumpTarget(entity, state), state);
                    }
                    break;
                case STATE_JUMP:
                    {
                        JumpTo(entity, GetNewJumpTarget(entity), STATE_IDLE);
                    }
                    break;
                default:
                    {
                        stateMachine.StartState(entity, state);
                    }
                    break;
            }
        }
        private class IdleState : EntityStateMachineState
        {
            public IdleState() : base(STATE_IDLE, ANIMATION_STATE_IDLE) { }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var stateTimer = stateMachine.GetStateTimer(entity);
                stateTimer.ResetSeconds(0.5f);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                if (GetRevivedTimes(entity) >= MAX_REVIVE_TIMES)
                {
                    SwitchState(entity, STATE_TIRED);
                }
                else if (ShouldTriggerNextJoke(entity))
                {
                    TriggerNextJoke(entity);
                }
                else
                {
                    UpdateStateSwitch(stateMachine, entity);
                }
            }
            private void UpdateStateSwitch(EntityStateMachine stateMachine, Entity entity)
            {
                var stateTimer = stateMachine.GetStateTimer(entity);
                stateTimer.Run(stateMachine.GetSpeed(entity));
                if (stateTimer.Expired)
                {
                    var nextIndex = stateMachine.GetNextStateIndex(entity);
                    int[] pool;
                    if (GetPhase(entity) == PHASE_1)
                    {
                        pool = statePoolPhase1;
                        nextIndex = pool.FindNextStateIndex(nextIndex, state => CanSwitchStatePhase1(entity, state));
                    }
                    else
                    {
                        pool = statePoolPhase2;
                        nextIndex = pool.FindNextStateIndex(nextIndex, state => CanSwitchStatePhase2(entity, state));
                    }
                    if (nextIndex >= 0)
                    {
                        var state = pool[nextIndex];
                        stateMachine.SetNextStateIndex(entity, nextIndex + 1);
                        SwitchState(entity, state);
                    }
                    else
                    {
                        stateTimer.Reset();
                    }
                }
            }
        }
        #endregion

        #region 跳跃
        private static Vector3 GetStateJumpTarget(Entity entity, int state)
        {
            switch (state)
            {
                case STATE_SPIT_TRASH:
                case STATE_HYPERBEAM:
                    {
                        var column = 8;
                        var lane = FindRandomLaneWithEnemies(entity);
                        return entity.Level.GetEntityGridPosition(column, lane);
                    }
                case STATE_PAY_TO_WIN:
                case STATE_BOMBARD:
                case STATE_SUMMON_WITHER:
                case STATE_GIANTIZE:
                case STATE_FIREBREATH:
                    {
                        var column = 8;
                        var lane = 2;
                        return entity.Level.GetEntityGridPosition(column, lane);
                    }
            }
            return GetNewJumpTarget(entity);
        }
        private static Vector2Int GetNewJumpTargetGridOffset(Entity entity)
        {
            var column = entity.GetColumn();
            var lane = entity.GetLane();
            var maxLane = entity.Level.GetMaxLaneCount();
            var directionX = entity.GetFacingX();
            if (column <= 1)
            {
                directionX = 1;
            }
            else if (column >= entity.Level.GetMaxColumnCount() - 2)
            {
                directionX = -1;
            }
            var possibleLaneOffsets = new List<int>();
            for (int side = 0; side < 2; side++)
            {
                var directionY = side * 2 - 1;
                for (int length = 1; length <= 2; length++)
                {
                    var laneOffset = directionY * length;
                    var targetLane = lane + laneOffset;
                    if (targetLane >= 0 && targetLane < maxLane)
                    {
                        possibleLaneOffsets.Add(laneOffset);
                    }
                }
            }
            var resultLaneOffset = 0;
            if (possibleLaneOffsets.Count > 0)
            {
                resultLaneOffset = possibleLaneOffsets.Random(entity.RNG);
            }
            return new Vector2Int(directionX * (3 - Mathf.Abs(resultLaneOffset)), resultLaneOffset);
        }
        private static Vector3 GetNewJumpTarget(Entity entity)
        {
            var offset = GetNewJumpTargetGridOffset(entity);
            return entity.Level.GetEntityGridPosition(entity.GetColumn() + offset.x, entity.GetLane() + offset.y);
        }
        private static void JumpTo(Entity boss, Vector3 targetPosition, int state)
        {
            SetNextJumpTarget(boss, targetPosition);
            SetNextJumpState(boss, state);
            stateMachine.StartState(boss, STATE_JUMP);
        }
        private static void StartJump(Entity boss, float inAirSeconds, Vector3 targetPosition)
        {
            var inAirTicks = Ticks.FromSeconds(inAirSeconds);
            Vector3 velocity = VanillaProjectileExt.GetLobVelocityByTime(boss.Position, targetPosition, inAirTicks, boss.GetGravity());
            boss.Velocity = velocity;
            SetFlipX(boss, targetPosition.x > boss.Position.x);
        }
        private class JumpState : EntityStateMachineState
        {
            public JumpState() : base(STATE_JUMP, ANIMATION_STATE_JUMP) { }
            public override int GetAnimationSubstate(int substate)
            {
                if (substate == SUBSTATE_END)
                {
                    return ANIMATION_SUBSTATE_JUMP_LAND;
                }
                return ANIMATION_SUBSTATE_JUMP_JUMP;
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                StartJump(entity, jumpFlyingSeconds, GetNextJumpTarget(entity));
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_START:
                        if (entity.IsOnGround)
                        {
                            entity.PlaySound(VanillaSoundID.wood);
                            stateMachine.StartSubState(entity, SUBSTATE_END);
                            timer.ResetSeconds(1 / 6f);
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            var nextState = GetNextJumpState(entity);
                            SetNextJumpState(entity, STATE_IDLE);
                            stateMachine.StartState(entity, nextState);
                        }
                        break;
                }
            }
            public const int SUBSTATE_START = 0;
            public const int SUBSTATE_END = 1;

            public const float jumpFlyingSeconds = 0.5f;
        }
        #endregion

        #region 冲刺
        private static Vector3 GetNewChargeTarget(Entity entity)
        {
            var offset = GetNewJumpTargetGridOffset(entity);
            offset.x += Math.Sign(offset.x) * 3;
            return entity.Level.GetEntityGridPosition(entity.GetColumn() + offset.x, entity.GetLane() + offset.y);
        }
        private static void ChargeCrush(Entity entity)
        {
            var level = entity.Level;
            crushBuffer.Clear();
            crushDetector.DetectMultiple(entity, crushBuffer);
            foreach (IEntityCollider collider in crushBuffer)
            {
                var ent = collider.Entity;
                var damageOutput = collider.TakeDamage(300, new DamageEffectList(VanillaDamageEffects.IMPACT, VanillaDamageEffects.IGNORE_ARMOR), entity);
                if (ent.Type == EntityTypes.PLANT)
                {
                    if (damageOutput?.BodyResult?.Fatal ?? false)
                    {
                        entity.PlaySound(VanillaSoundID.smash);
                    }
                }
            }
        }
        private class ChargeState : EntityStateMachineState
        {
            public ChargeState() : base(STATE_CHARGE, ANIMATION_STATE_JUMP) { }
            public override int GetAnimationState(int substate)
            {
                if (substate == SUBSTATE_SHAKE)
                {
                    return ANIMATION_STATE_IDLE;
                }
                return base.GetAnimationState(substate);
            }
            public override int GetAnimationSubstate(int substate)
            {
                if (substate == SUBSTATE_END)
                {
                    return ANIMATION_SUBSTATE_LAND;
                }
                return ANIMATION_SUBSTATE_JUMP;
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.ResetSeconds(1);
                SetShake(entity, true);
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
                SetShake(entity, false);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_SHAKE:
                        if (timer.Expired)
                        {
                            StartJump(entity, jumpFlyingSeconds, GetNewChargeTarget(entity));
                            stateMachine.StartSubState(entity, SUBSTATE_CHARGE1);
                            SetShake(entity, false);
                        }
                        break;
                    case SUBSTATE_CHARGE1:
                    case SUBSTATE_CHARGE2:
                        {
                            SpawnShadow(entity);
                            if (entity.IsOnGround)
                            {
                                entity.PlaySound(VanillaSoundID.wood);
                                StartJump(entity, jumpFlyingSeconds, GetNewChargeTarget(entity));
                                ChargeCrush(entity);
                                stateMachine.StartSubState(entity, substate + 1);
                            }
                        }
                        break;
                    case SUBSTATE_CHARGE3:
                        {
                            SpawnShadow(entity);
                            if (entity.IsOnGround)
                            {
                                entity.PlaySound(VanillaSoundID.wood);
                                ChargeCrush(entity);
                                stateMachine.StartSubState(entity, SUBSTATE_END);
                                timer.ResetSeconds(1 / 6f);
                            }
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public const int SUBSTATE_SHAKE = 0;
            public const int SUBSTATE_CHARGE1 = 1;
            public const int SUBSTATE_CHARGE2 = 2;
            public const int SUBSTATE_CHARGE3 = 3;
            public const int SUBSTATE_END = 4;

            public const int ANIMATION_SUBSTATE_JUMP = 0;
            public const int ANIMATION_SUBSTATE_LAND = 1;

            public const float jumpFlyingSeconds = 0.5f;
        }
        #endregion

        #region 高跳
        private static Entity? FindHighJumpSmashTargetEntity(Entity entity)
        {
            bool haveBeenPricked = HaveBeenPricked(entity);

            IEnumerable<Entity> validEntities;
            highJumpSearchBuffer.Clear();
            if (!haveBeenPricked)
            {
                entity.Level.FindEntitiesNonAlloc(e => IsValidAttackTarget(entity, e), highJumpSearchBuffer);
                validEntities = highJumpSearchBuffer.Where(e => e.IsEntityOf(VanillaContraptionID.amethystPylon));
                if (validEntities.Count() <= 0)
                {
                    validEntities = highJumpSearchBuffer;
                }
            }
            else
            {
                entity.Level.FindEntitiesNonAlloc(e => IsValidAttackTarget(entity, e) && !e.IsEntityOf(VanillaContraptionID.amethystPylon), highJumpSearchBuffer);
                validEntities = highJumpSearchBuffer;
            }
            if (validEntities.Count() <= 0)
                return null;
            return validEntities.Random(entity.RNG);
        }
        private static Vector3 FindHighJumpSmashTarget(Entity entity)
        {
            var target = FindHighJumpSmashTargetEntity(entity);
            Vector3 position;
            if (target == null)
            {
                position = entity.Position;
            }
            else
            {
                position = target.Position;
            }
            position.y = entity.Level.GetGroundY(position.x, position.z);
            return position;
        }
        public static void PrickHighJump(Entity entity, Entity source)
        {
            if (stateMachine.GetStateNumber(entity) != STATE_SMASH)
                return;
            stateMachine.StartSubState(entity, HighJumpState.SUBSTATE_PRICKED);
            entity.SetProperty(PROP_GRAVITY_MULTIPLIER, 0f);
            var timer = stateMachine.GetSubStateTimer(entity);
            timer.ResetSeconds(1);
            SetShake(entity, true);
            SetHaveBeenPricked(entity, true);

            RemoveSmashTarget(entity);

            var pos = entity.Position;
            var vel = entity.Velocity;
            pos.y = source.GetBounds().max.y;
            vel.y = 0;
            entity.Position = pos;
            entity.Velocity = vel;

            // 伤害放最后，让死亡状态最后触发。
            entity.TakeDamage(600, new DamageEffectList(VanillaDamageEffects.SLICE), source);

            entity.Spawn(VanillaEffectID.stabEffect, (entity.Position + source.Position) / 2);


            entity.PlaySound(VanillaSoundID.shieldHit);
            entity.PlaySound(VanillaSoundID.lockedChestOuch);
        }
        private class HighJumpState : EntityStateMachineState
        {
            public HighJumpState() : base(STATE_SMASH, ANIMATION_STATE_SMASH) { }
            public override int GetAnimationState(int substate)
            {
                if (substate == SUBSTATE_SHAKE)
                {
                    return ANIMATION_STATE_IDLE;
                }
                return base.GetAnimationState(substate);
            }
            public override int GetAnimationSubstate(int substate)
            {
                if (substate == SUBSTATE_FALL || substate == SUBSTATE_END)
                {
                    return ANIMATION_SUBSTATE_SMASH_FALL;
                }
                return ANIMATION_SUBSTATE_SMASH_JUMP;
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.ResetSeconds(1);
                SetShake(entity, true);
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
                SetShake(entity, false);

                RemoveSmashTarget(entity);
                entity.SetProperty(PROP_GRAVITY_MULTIPLIER, 1f);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_SHAKE:
                        if (timer.Expired)
                        {
                            stateMachine.StartSubState(entity, SUBSTATE_JUMP);
                            timer.ResetSeconds(1);
                            SetShake(entity, false);
                            var position = FindHighJumpSmashTarget(entity);
                            SetNextJumpTarget(entity, position);
                            SpawnSmashTarget(entity, position);

                            entity.PlaySound(VanillaSoundID.launch);
                        }
                        break;
                    case SUBSTATE_JUMP:
                        {
                            entity.Velocity = Vector3.up * 100;
                            SpawnShadow(entity);
                            if (timer.Expired)
                            {
                                stateMachine.StartSubState(entity, SUBSTATE_FALL);
                            }
                        }
                        break;
                    case SUBSTATE_FALL:
                        {
                            var targetPosition = GetNextJumpTarget(entity);
                            var velocity = (targetPosition - entity.Position) * 0.8f;
                            velocity.y = -50;
                            entity.Velocity = velocity;

                            SpawnShadow(entity, true);
                            if (entity.IsOnGround)
                            {
                                float damage = VanillaMod.INSTA_DAMAGE_AMOUNT;
                                HighJumpSmash(entity, damage);

                                stateMachine.StartSubState(entity, SUBSTATE_END);
                                timer.ResetSeconds(1);

                                RemoveSmashTarget(entity);
                                entity.PlaySound(VanillaSoundID.smash);
                                entity.Level.ShakeScreen(10, 0, 15);
                            }
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                    case SUBSTATE_PRICKED:
                        entity.Velocity = Vector3.zero;
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public static void HighJumpSmash(Entity entity, float damage)
            {
                highJumpDamageBuffer.Clear();
                highJumpDetector.DetectMultiple(entity, highJumpDamageBuffer);
                foreach (var target in highJumpDamageBuffer)
                {
                    target.TakeDamage(damage, new DamageEffectList(VanillaDamageEffects.EXPLOSION, VanillaDamageEffects.IGNORE_ARMOR), entity);
                }
            }
            public const int SUBSTATE_SHAKE = 0;
            public const int SUBSTATE_JUMP = 1;
            public const int SUBSTATE_FALL = 2;
            public const int SUBSTATE_END = 3;
            public const int SUBSTATE_PRICKED = 4;
        }
        #endregion

        #region 封锁
        private static bool CanSwitchToLockState(Entity entity)
        {
            var level = entity.Level;
            var seedPacks = GetBlueprintsToLock(level);
            if (seedPacks.Count() <= 0)
                return false;
            return true;
        }
        public static IEnumerable<SeedPack> GetBlueprintsToLock(LevelEngine level)
        {
            if (level.IsConveyorMode())
            {
                return level.GetAllConveyorSeedPacks();
            }
            else
            {
                return level.GetAllSeedPacks().OfType<SeedPack>();
            }
        }
        public static void LockRandomBlueprint(Entity entity, int count)
        {
            var level = entity.Level;
            var seedPacks = GetBlueprintsToLock(level);
            if (seedPacks.Count() <= 0)
                return;
            var selected = seedPacks.RandomTake(count, entity.RNG);
            if (selected == null)
                return;
            foreach (var seedPack in selected)
            {
                seedPack.AddBuff<BlueprintLockBuff>();
            }
        }
        private class LockState : EntityStateMachineState
        {
            public LockState() : base(STATE_LOCK, ANIMATION_STATE_IDLE) { }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.ResetSeconds(1);
                SetShake(entity, true);
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
                SetShake(entity, false);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_SHAKE:
                        if (timer.Expired)
                        {
                            stateMachine.StartSubState(entity, SUBSTATE_LOCK);
                            timer.ResetSeconds(1);

                            LockRandomBlueprint(entity, LOCK_BLUEPRINT_COUNT);
                            entity.Spawn(VanillaEffectID.lockSigil, entity.GetCenter());

                            entity.Level.ShakeScreen(10, 0, 15);
                            entity.PlaySound(VanillaSoundID.locked);
                            SetShake(entity, false);
                        }
                        break;
                    case SUBSTATE_LOCK:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public const int SUBSTATE_SHAKE = 0;
            public const int SUBSTATE_LOCK = 1;
        }
        #endregion

        #region 粉碎之锁
        private static bool CanSwitchToCrushingLockState(Entity entity)
        {
            return FindCrushingLockTargetGridIndexes(entity).Count() > 0 && GetPossibleRequiredContraptionID(entity.Level).Count() > 0;
        }
        public static IEnumerable<int> FindCrushingLockTargetGridIndexes(Entity entity)
        {
            var level = entity.Level;
            int columnCount = level.GetMaxColumnCount();
            int laneCount = level.GetMaxLaneCount();
            int maxIndex = columnCount * laneCount;

            // 使用数组代替字典，内存连续、访问更快（索引范围已知）
            var contraptions = new bool[maxIndex];
            var neighborCounts = new int[maxIndex];

            // 先记录所有植物的位置
            foreach (var contraption in level.FindEntities(e => e.Type == EntityTypes.PLANT))
            {
                int idx = contraption.GetGridIndex();
                if (!contraption.CanDeactive())
                    continue;
                if ((uint)idx < (uint)maxIndex)   // 边界检查的惯用高效写法
                    contraptions[idx] = true;
            }

            // 统计每个格子周围 8 格的植物数量
            for (int idx = 0; idx < maxIndex; idx++)
            {
                if (!contraptions[idx])
                    continue;

                int x = level.GetGridColumnByIndex(idx);
                int y = level.GetGridLaneByIndex(idx);

                int count = 0;
                for (int dx = -1; dx <= 1; dx++)
                {
                    int nx = x + dx;
                    if ((uint)nx >= (uint)columnCount)
                        continue;
                    for (int dy = -1; dy <= 1; dy++)
                    {
                        if (dx == 0 && dy == 0)
                            continue;
                        int ny = y + dy;
                        if ((uint)ny >= (uint)laneCount)
                            continue;
                        int neighborIdx = ny * columnCount + nx; // 直接计算，避免方法调用
                                                                 // 相邻格子只要有植物（或未来可能有机关）就算一次
                                                                 // 此处简单起见，有植物就算一次“包围”
                        if (contraptions[neighborIdx])
                            count++;
                    }
                }
                neighborCounts[idx] = count;
            }

            // 找出存活植物中 neighborCounts 最大的那个
            List<int> bestItems = new List<int>();
            float maxCount = 0;

            for (int i = 0; i < maxIndex; i++)
            {
                if (!contraptions[i])
                    continue;
                var count = neighborCounts[i];
                if (count > maxCount)
                {
                    maxCount = count;
                    bestItems.Clear();
                    bestItems.Add(i);
                }
                else if (count == maxCount)
                {
                    bestItems.Add(i);
                }
            }

            return bestItems;
        }
        public static IEnumerable<SeedPack> GetPossibleRequiredContraptionID(LevelEngine level)
        {
            IEnumerable<SeedPack> seedPacks;
            if (level.IsConveyorMode())
            {
                seedPacks = level.GetAllConveyorSeedPacks();
            }
            else
            {
                seedPacks = level.GetAllSeedPacks().OfType<SeedPack>();
            }
            return seedPacks.Where(s =>
            {
                if (s.IsUpgradeBlueprint() || s.CanInstantTrigger() || s.GetSeedType() != SeedTypes.ENTITY)
                    return false;
                if (s.IsDisabled())
                    return false;
                var entityID = s.GetSeedEntityID();
                var entityDef = level.Content.GetEntityDefinition(entityID);
                if (entityDef == null)
                    return false;
                var gridLayers = entityDef.GetGridLayersToTake();
                if (gridLayers == null || !gridLayers.Contains(VanillaGridLayers.main))
                    return false;
                return true;
            });
        }
        public static NamespaceID? GetRandomRequiredContraptionID(LevelEngine level, RandomGenerator rng)
        {
            var validSeedPacks = GetPossibleRequiredContraptionID(level);
            if (validSeedPacks.Count() <= 0)
                return null;
            return validSeedPacks.Random(rng).GetSeedEntityID();
        }
        public static void CrushingLock(Entity entity)
        {
            var gridIndexes = FindCrushingLockTargetGridIndexes(entity);
            if (gridIndexes.Count() <= 0)
                return;
            var rng = entity.RNG;
            var gridIndex = gridIndexes.Random(rng);
            var grid = entity.Level.GetGrid(gridIndex);
            if (grid == null)
                return;
            var damageEffects = new DamageEffectList(VanillaDamageEffects.INSTA_KILL);
            foreach (var ent in grid.GetEntities())
            {
                ent.Die(damageEffects, entity);
            }
            var requiredID = GetRandomRequiredContraptionID(entity.Level, rng);
            if (requiredID != null)
            {
                PsychicShackle.Spawn(entity.Level, grid.GetEntityPosition(), requiredID, entity);
            }
        }
        private class CrushingLockState : EntityStateMachineState
        {
            public CrushingLockState() : base(STATE_CRUSHING_LOCK, ANIMATION_STATE_IDLE) { }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.ResetSeconds(1);
                SetShake(entity, true);
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
                SetShake(entity, false);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_SHAKE:
                        if (timer.Expired)
                        {
                            stateMachine.StartSubState(entity, SUBSTATE_LOCK);
                            timer.ResetSeconds(1);

                            CrushingLock(entity);
                            entity.Spawn(VanillaEffectID.lockSigil, entity.GetCenter());

                            entity.Level.ShakeScreen(10, 0, 15);
                            entity.PlaySound(VanillaSoundID.locked);
                            entity.PlaySound(VanillaSoundID.smash);
                            SetShake(entity, false);
                        }
                        break;
                    case SUBSTATE_LOCK:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public const int SUBSTATE_SHAKE = 0;
            public const int SUBSTATE_LOCK = 1;
        }
