                        {
                            stateMachine.StartSubState(entity, SUBSTATE_OPEN);
                            timer.ResetSeconds(1);
                            SetShake(entity, false);
                            entity.PlaySound(VanillaSoundID.chestOpen);

                            var pos = entity.Position;
