                        {
                            stateMachine.StartSubState(entity, SUBSTATE_CLOSE);
                            timer.ResetSeconds(1);
                            entity.PlaySound(VanillaSoundID.chestClose);
                        }
                        break;
                    case SUBSTATE_CLOSE:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
