        #region 召唤凋灵
        private class SummonWitherState : EntityStateMachineState
        {
            public SummonWitherState() : base(STATE_SUMMON_WITHER, ANIMATION_STATE_IDLE) { }
            public override int GetAnimationState(int substate)
            {
                switch (substate)
                {
                    case SUBSTATE_SKULL1:
                    case SUBSTATE_SKULL2:
                    case SUBSTATE_SKULL3:
                    case SUBSTATE_JUMP1:
                    case SUBSTATE_JUMP2:
                    case SUBSTATE_JUMP3:
                        return ANIMATION_STATE_JUMP;
                    default:
                        return base.GetAnimationState(substate);
                }
            }
            public override int GetAnimationSubstate(int substate)
            {
                switch (substate)
                {
                    case SUBSTATE_SKULL1:
                    case SUBSTATE_SKULL2:
                    case SUBSTATE_SKULL3:
                    case SUBSTATE_JUMP1:
                    case SUBSTATE_JUMP2:
                    case SUBSTATE_JUMP3:
                        return ANIMATION_SUBSTATE_JUMP_JUMP;
                    default:
                        return base.GetAnimationSubstate(substate);
                }
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                SetFlipX(entity, false);
                entity.AddBuff<LockedChestInvincibleBuff>();

                entity.PlaySound(VanillaSoundID.lockedChestGiggles);
                Hop(entity);
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
                entity.RemoveBuffs<LockedChestInvincibleBuff>();

                SetEmote(entity, EMOTE_NONE);
                var blocks = GetBlocks(entity);
                if (blocks.ExistsAndAlive())
                {
                    blocks.Die(new DamageEffectList(VanillaDamageEffects.INSTA_KILL), entity);
                }
                SetStateTargetID(entity, null);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_HOP1:
                    case SUBSTATE_HOP2:
                        if (entity.IsOnGround)
                        {
                            Hop(entity);
                            entity.PlaySound(VanillaSoundID.wood);
                            stateMachine.StartSubState(entity, substate + 1);
                        }
                        break;
                    case SUBSTATE_HOP3:
                        if (entity.IsOnGround)
                        {
                            entity.PlaySound(VanillaSoundID.wood);

                            stateMachine.StartSubState(entity, SUBSTATE_SOULSAND1);
                            timer.ResetSeconds(0.5f);

                            entity.SpawnWithParams(VanillaEffectID.witherSummoningBlocks, entity.Position + entity.GetFacingDirection() * 80)?.Let(b =>
                            {
                                SetStateTargetID(entity, new EntityID(b));
                                b.PlaySound(VanillaSoundID.soulSand);
                            });
                        }
                        break;

                    case SUBSTATE_SOULSAND1:
                    case SUBSTATE_SOULSAND2:
                    case SUBSTATE_SOULSAND3:
                        if (timer.Expired)
                        {
                            stateMachine.StartSubState(entity, substate + 1);
                            timer.ResetSeconds(0.5f);
                            if (substateProgresses.TryGetValue(substate, out var progress))
                            {
                                BuildBlock(entity, progress, VanillaSoundID.soulSand);
                            }
                        }
                        break;
                    case SUBSTATE_SOULSAND4:
                    case SUBSTATE_SKULL1:
                    case SUBSTATE_SKULL2:
                        if (entity.IsOnGround)
                        {
                            Hop(entity, 20);
                            stateMachine.StartSubState(entity, substate + 1);
                        }
                        break;
                    case SUBSTATE_SKULL3:
                        if (entity.IsOnGround)
                        {
                            stateMachine.StartSubState(entity, SUBSTATE_DUMB);
                            timer.ResetSeconds(5f);
                        }
                        break;
                    case SUBSTATE_JUMP1:
                    case SUBSTATE_JUMP2:
                        if (entity.Velocity.y <= 0.00001f) // 在向上跳，还没有放置头颅的情况下被石化，解除石化后会导致状态卡死，所以用小于0.000001
                        {
                            stateMachine.StartSubState(entity, substate + 1);
                            if (substateProgresses.TryGetValue(substate, out var progress))
                            {
                                BuildBlock(entity, progress, VanillaSoundID.stone);
                            }
                        }
                        break;
                    case SUBSTATE_JUMP3:
                        if (entity.Velocity.y <= 0.00001f) // 在向上跳，还没有放置头颅的情况下被石化，解除石化后会导致状态卡死，所以用小于0.000001
                        {
                            var blocks = GetBlocks(entity);
                            if (blocks.ExistsAndAlive())
                            {
                                blocks.PlaySound(VanillaSoundID.stone);
                                blocks.Die(new DamageEffectList(VanillaDamageEffects.INSTA_KILL), entity);
                                blocks.Spawn(VanillaBossID.pinkWither, blocks.Position);
                                SetStateTargetID(entity, null);
                            }
                            stateMachine.StartSubState(entity, SUBSTATE_SKULL3);
                        }
                        break;
                    case SUBSTATE_DUMB:
                        if (timer.Expired)
                        {
                            ShowQuestion(entity);
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public static Entity? GetBlocks(Entity entity)
            {
                return GetStateTargetID(entity)?.GetEntity(entity.Level);
            }
            public static void ShowQuestion(Entity entity)
            {
                SetEmote(entity, EMOTE_QUESTION);
                stateMachine.StartSubState(entity, SUBSTATE_END);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.ResetSeconds(1f);
                entity.PlaySound(VanillaSoundID.pop);
            }
            public static void BuildBlock(Entity entity, int progress, NamespaceID soundID)
            {
                var blocks = GetBlocks(entity);
                if (blocks.ExistsAndAlive())
                {
                    blocks.SetModelProperty("Progress", progress);
                    blocks.PlaySound(soundID);
                }
                else
                {
                    ShowQuestion(entity);
                }
            }
            public const int SUBSTATE_HOP1 = 0;
            public const int SUBSTATE_HOP2 = 1;
            public const int SUBSTATE_HOP3 = 2;
            public const int SUBSTATE_SOULSAND1 = 3;
            public const int SUBSTATE_SOULSAND2 = 4;
            public const int SUBSTATE_SOULSAND3 = 5;
            public const int SUBSTATE_SOULSAND4 = 6;
            public const int SUBSTATE_JUMP1 = 7;
            public const int SUBSTATE_SKULL1 = 8;
            public const int SUBSTATE_JUMP2 = 9;
            public const int SUBSTATE_SKULL2 = 10;
            public const int SUBSTATE_JUMP3 = 11;
            public const int SUBSTATE_SKULL3 = 12;
            public const int SUBSTATE_DUMB = 13;
            public const int SUBSTATE_END = 14;

            public static Dictionary<int, int> substateProgresses = new Dictionary<int, int>()
            {
                { SUBSTATE_SOULSAND1, 1 },
                { SUBSTATE_SOULSAND2, 2 },
                { SUBSTATE_SOULSAND3, 3 },
                { SUBSTATE_JUMP1, 4 },
                { SUBSTATE_JUMP2, 5 },
            };
        }
