                var grids = entity.Level.GetAllGrids();
                foreach (var grid in grids)
                {
                    entity.Spawn(VanillaContraptionID.tnt, grid.GetEntityPosition() + Vector3.up * 1000, spawnParams)?.Let(tnt =>
                    {
